def _trusted_orderbook_touch_ticks(*, price=10_000, count=10, hhmm="10:00"):
    ticks = []
    for idx in range(count):
        ticks.append(
            {
                "time": f"{hhmm}:{10 - idx:02d}",
                "price": price,
                "volume": 10 + idx,
                "best_ask": price,
                "best_bid": price - 10,
                "aggressor_source": "orderbook_touch",
                "aggressor_quality": "touch_or_crossed_ask",
                "aggressor_quote_source": "inline_0B_top_of_book",
                "strength": 120.0,
            }
        )
    return ticks


def _micro_vwap_candles(*, price=10_000, count=5):
    now = datetime.now()
    return [
        {
            "체결시간": (now - timedelta(minutes=(count - idx - 1))).strftime("%H:%M:%S"),
            "현재가": price,
            "고가": price + 20,
            "저가": price - 20,
            "거래량": 1_000 + idx,
        }
        for idx in range(count)
    ]


def test_caution_weak_liquidity_combo_is_observation_only_for_rising_missed(monkeypatch):
    monkeypatch.delenv("KORSTOCKSCAN_CAUTION_WEAK_LIQUIDITY_ENTRY_BLOCK_ENABLED", raising=False)
    monkeypatch.delenv("KORSTOCKSCAN_RISING_MISSED_CAUTION_WEAK_LIQUIDITY_BLOCK_ENABLED", raising=False)

    decision = state_handlers._evaluate_caution_weak_liquidity_entry_block(
        stock={"rising_missed_normal_buy_bridge_allowed": True},
        runtime={},
        strategy="SCALPING",
        latency_gate={
            "latency_state": "CAUTION",
            "entry_price_gap_profile": "weak_liquidity_wide_spread",
        },
        guard_fields={
            "pre_submit_liquidity_guard_action": "NOT_AVAILABLE",
            "pre_submit_liquidity_reason": "liquidity_not_available",
        },
    )

    assert decision["blocked"] is False
    assert decision["block_reason"] == "ok"
    assert decision["threshold_family"] == "caution_weak_liquidity_entry_block"
    assert decision["rising_missed_entry_lineage"] is True
    assert decision["rising_missed_liquidity_observation_only"] is True
    assert decision["decision_authority"] == "rising_missed_liquidity_attribution_only"
    assert decision["gate_action"] == "observe_only"
    assert decision["runtime_effect"] is False
    assert decision["actual_order_submitted"] is False
    assert decision["broker_order_forbidden"] is False


