def test_same_symbol_loss_reentry_cooldown_targets_loss_exits_only():
    from src.utils.constants import TRADING_RULES as CONFIG

    class _RulesProxy:
        def __init__(self, base, **overrides):
            self._base = base
            self._overrides = overrides

        def __getattr__(self, name):
            if name in self._overrides:
                return self._overrides[name]
            return getattr(self._base, name)

    state_handlers.TRADING_RULES = _RulesProxy(
        CONFIG,
        SCALP_SAME_SYMBOL_LOSS_REENTRY_COOLDOWN_ENABLED=True,
        SCALP_SAME_SYMBOL_LOSS_REENTRY_COOLDOWN_SEC=3600,
    )

    assert state_handlers._resolve_same_symbol_loss_reentry_cooldown_sec("scalp_hard_stop_pct", -2.5) == 3600
    assert state_handlers._resolve_same_symbol_loss_reentry_cooldown_sec("scalp_soft_stop_pct", -1.5) == 3600
    assert state_handlers._resolve_same_symbol_loss_reentry_cooldown_sec("scalp_preset_hard_stop_pct", -0.7) == 3600
    assert state_handlers._resolve_same_symbol_loss_reentry_cooldown_sec("protect_trailing_stop", -0.01) == 3600
    assert (
        state_handlers._resolve_same_symbol_loss_reentry_cooldown_sec(
            "scalp_bad_entry_refined_canary",
            -1.2,
        )
        == 3600
    )
    assert state_handlers._resolve_same_symbol_loss_reentry_cooldown_sec("scalp_trailing_take_profit", 1.2) == 0
    assert state_handlers._resolve_same_symbol_loss_reentry_cooldown_sec("scalp_trailing_take_profit", -0.2) == 3600
    assert state_handlers._resolve_same_symbol_loss_reentry_cooldown_sec("protect_trailing_stop", 0.19) == 0


def test_scalp_same_symbol_loss_reentry_guard_records_and_blocks(monkeypatch):
    original_rules = state_handlers.TRADING_RULES
    try:
        state_handlers.TRADING_RULES = replace(
            CONFIG,
            SCALP_SAME_SYMBOL_LOSS_REENTRY_COOLDOWN_ENABLED=True,
            SCALP_SAME_SYMBOL_LOSS_REENTRY_COOLDOWN_SEC=3600,
        )
        state_handlers._SCALP_SAME_SYMBOL_LOSS_REENTRY_COOLDOWNS.clear()

        row = state_handlers._record_scalp_same_symbol_loss_reentry_cooldown(
            "000500",
            stock={"name": "가온전선"},
            exit_rule="scalp_soft_stop_pct",
            profit_rate=-2.11,
            now_ts=1_000.0,
            cooldown_sec=3600,
        )

        assert row["expires_at"] == 4_600.0
        decision = state_handlers.evaluate_scalp_same_symbol_loss_reentry_guard("000500", 1_100.0)
        assert decision["allowed"] is False
        assert decision["reason"] == "same_symbol_loss_reentry_cooldown"
        assert decision["cooldown_remaining_sec"] == 3500
        assert decision["last_exit_rule"] == "scalp_soft_stop_pct"
        assert decision["last_exit_profit_rate"] == -2.11

        expired = state_handlers.evaluate_scalp_same_symbol_loss_reentry_guard("000500", 4_601.0)
        assert expired["allowed"] is True
        assert "000500" not in state_handlers._SCALP_SAME_SYMBOL_LOSS_REENTRY_COOLDOWNS
    finally:
        state_handlers._SCALP_SAME_SYMBOL_LOSS_REENTRY_COOLDOWNS.clear()
        state_handlers.TRADING_RULES = original_rules


def test_scalp_loss_reentry_rebound_bypass_allows_strong_scanner_canary(monkeypatch):
    original_rules = state_handlers.TRADING_RULES
    logs = []
    try:
        state_handlers.TRADING_RULES = replace(
            CONFIG,
            SCALP_SAME_SYMBOL_LOSS_REENTRY_COOLDOWN_ENABLED=True,
            SCALP_SAME_SYMBOL_LOSS_REENTRY_COOLDOWN_SEC=3600,
            SCALP_LOSS_REENTRY_REBOUND_BYPASS_ENABLED=True,
            SCALP_LOSS_REENTRY_REBOUND_MIN_DELTA_PCT=4.0,
            SCALP_LOSS_REENTRY_REBOUND_FORCE_QTY=1,
        )
        state_handlers._SCALP_SAME_SYMBOL_LOSS_REENTRY_COOLDOWNS.clear()
        monkeypatch.setattr(
            state_handlers,
            "_log_entry_pipeline",
            lambda stock, code, stage, **fields: logs.append((stage, fields)),
        )
        stock = {
            "code": "000500",
            "name": "가온전선",
            "strategy": "SCALPING",
            "scanner_promotion_id": "scan-1",
            "scanner_promotion_emitted_epoch": "1001.000",
            "entry_armed_at_epoch": 1001.0,
            "buy_price": 10000,
            "scanner_promotion_reason": "price_jump_start_acceleration",
            "source_signature": "PRICE_JUMP_START,VOLUME_SURGE_POSITIVE,REALTIME_RANK_START",
            "first_seen_price": "10000",
            "current_price": "10600",
            "current_price_observed": "10600",
            "price_delta_since_first_seen_pct": "6.00",
        }
        state_handlers._record_scalp_same_symbol_loss_reentry_cooldown(
            "000500",
            stock=stock,
            exit_rule="scalp_soft_stop_pct",
            profit_rate=-3.56,
            now_ts=1_000.0,
            cooldown_sec=3600,
        )
        guard = state_handlers.evaluate_scalp_same_symbol_loss_reentry_guard("000500", 1_100.0)

        bypass = state_handlers._evaluate_scalp_loss_reentry_rebound_bypass(
            stock,
            "000500",
            {"curr": 10600, "last_ws_update_ts": state_handlers.time.time()},
            guard,
            now_ts=1_100.0,
            source_stage="watching_pre_ai",
        )
        state_handlers._apply_scalp_loss_reentry_rebound_bypass(
            stock,
            "000500",
            bypass,
            now_ts=1_100.0,
            cooldowns={"000500": 4_600.0},
        )
        capped = state_handlers._apply_scalp_loss_reentry_rebound_canary_qty(
            stock,
            strategy="SCALPING",
            curr_price=10600,
            deposit=1_000_000,
            target_budget=300_000,
            safe_budget=300_000,
            real_buy_qty=28,
            used_safety_ratio=0.8,
            bypass=bypass,
        )

        assert bypass["allowed"] is True
        assert stock["loss_reentry_rebound_canary_entry"] is True
        assert "000500" not in state_handlers._SCALP_SAME_SYMBOL_LOSS_REENTRY_COOLDOWNS
        assert capped == (10600, 10600, 1, 1.0, True)
        assert logs[-1][0] == "scalp_loss_reentry_rebound_bypass"
    finally:
        state_handlers._SCALP_SAME_SYMBOL_LOSS_REENTRY_COOLDOWNS.clear()
        state_handlers.TRADING_RULES = original_rules


