def test_late_loss_avg_down_retry_uses_reversal_qty_rule(monkeypatch):
    scale_in.TRADING_RULES = replace(
        CONFIG,
        MAX_POSITION_PCT=1.0,
        SCALPING_SCALE_IN_DYNAMIC_QTY_ENABLED=True,
        REVERSAL_ADD_SIZE_RATIO=0.33,
        REVERSAL_ADD_MIN_QTY_FLOOR_ENABLED=True,
    )
    stock = {
        "strategy": "SCALPING",
        "buy_price": 10_000,
        "buy_qty": 1,
        "rt_ai_prob": 0.67,
    }
    price_resolution = {"allowed": True, "order_price": 9_900}

    late = scale_in.describe_dynamic_scale_in_qty(
        stock=stock,
        resolved_price=9_900,
        deposit=100_000,
        add_type="AVG_DOWN",
        strategy="SCALPING",
        add_reason="late_loss_avg_down_retry",
        price_resolution=price_resolution,
        action={"current_ai_score": 67, "profit_rate": -2.0, "peak_profit": 1.0},
    )
    reversal = scale_in.describe_dynamic_scale_in_qty(
        stock=stock,
        resolved_price=9_900,
        deposit=100_000,
        add_type="AVG_DOWN",
        strategy="SCALPING",
        add_reason="reversal_add_ok",
        price_resolution=price_resolution,
        action={"current_ai_score": 67, "profit_rate": -2.0, "peak_profit": 1.0},
    )

    assert late["qty"] == reversal["qty"]
    assert late["qty"] > 0
    assert late["floor_applied"] == reversal["floor_applied"] is True

    stop_touch_mandatory = scale_in.describe_dynamic_scale_in_qty(
        stock={**stock, "buy_qty": 8},
        resolved_price=9_900,
        deposit=100_000,
        add_type="AVG_DOWN",
        strategy="SCALPING",
        add_reason="stop_line_touch_mandatory_avg_down",
        price_resolution={**price_resolution, "price_source": "stop_line_touch_market"},
        action={"current_ai_score": 50, "profit_rate": -3.65, "peak_profit": 0.31},
    )
    assert stop_touch_mandatory["qty"] > 0
    assert stop_touch_mandatory["qty_reason"] != "reversal_probe_missing"


def test_stop_line_touch_mandatory_avg_down_includes_ollix_like_case(monkeypatch):
    state_handlers.TRADING_RULES = replace(
        CONFIG,
        DEEP_RECOVERY_AVG_DOWN_ENABLED=True,
        DEEP_RECOVERY_AVG_DOWN_MAX_PER_POSITION=1,
    )
    stock = {
        "id": 13961,
        "code": "226950",
        "name": "올릭스",
        "status": "HOLDING",
        "strategy": "SCALPING",
        "buy_price": 166_300,
        "buy_qty": 8,
        "actual_order_submitted": True,
        "last_reversal_features": {
            "buy_pressure_10t": 82.0,
            "tick_acceleration_ratio": 1.08,
            "large_sell_print_detected": False,
            "curr_vs_micro_vwap_bp": 1.5,
            "micro_vwap_available": True,
            "minute_candle_window_fresh": True,
            "minute_candle_context_quality": "fresh_bar_window",
            "tick_context_quality": "live_tick",
            "tick_context_stale": False,
            "tick_latest_age_ms": 250,
            "tick_aggressor_trusted_count": 5,
            "tick_aggressor_pressure_usable": True,
            "quote_stale": False,
            "quote_age_ms": 450,
        },
        **_fresh_holding_score_fields(70, now_ts=1_000.0),
    }

    result = state_handlers._evaluate_stop_line_touch_mandatory_avg_down(
        stock,
        strategy="SCALPING",
        sell_reason_type="LOSS",
        exit_rule="scalp_soft_stop_pct",
        profit_rate=-3.65,
        peak_profit=0.31,
        current_ai_score=70,
        held_sec=180,
        dynamic_stop_pct=-3.00,
    )

    assert result["should_retry"] is True
    assert result["reason"] == "deep_recovery_avg_down"
    assert result["action"]["add_type"] == "AVG_DOWN"
    assert result["action"]["reason"] == "deep_recovery_avg_down"
    assert result["action"]["stop_line_touched"] is True
    assert result["action"]["stop_line_pct"] == -3.00
    assert result["action"]["stop_line_source"] == "scalp_soft_stop_pct"

    hard_stop_touch = state_handlers._evaluate_stop_line_touch_mandatory_avg_down(
        stock,
        strategy="SCALPING",
        sell_reason_type="LOSS",
        exit_rule="scalp_hard_stop_pct",
        profit_rate=-3.65,
        peak_profit=0.31,
        current_ai_score=70,
        held_sec=180,
        dynamic_stop_pct=-2.50,
    )
    assert hard_stop_touch["should_retry"] is True
    assert hard_stop_touch["action"]["stop_line_source"] == "scalp_hard_stop_pct"
    assert hard_stop_touch["action"]["stop_line_pct"] == -2.50

    stock["stop_line_touch_avg_down_used"] = True
    stock["stop_line_touch_avg_down_count"] = 1
    second_allowed = state_handlers._evaluate_stop_line_touch_mandatory_avg_down(
        stock,
        strategy="SCALPING",
        sell_reason_type="LOSS",
        exit_rule="scalp_soft_stop_pct",
        profit_rate=-3.65,
        peak_profit=0.31,
        current_ai_score=70,
        held_sec=180,
        dynamic_stop_pct=-3.00,
    )
    assert second_allowed["should_retry"] is False
    assert second_allowed["reason"] == "already_used"
    assert second_allowed["used_count"] == 1
    assert second_allowed["max_per_position"] == 1
    assert second_allowed["configured_max_per_position"] == 1

    stock["stop_line_touch_avg_down_count"] = 3
    already_used = state_handlers._evaluate_stop_line_touch_mandatory_avg_down(
        stock,
        strategy="SCALPING",
        sell_reason_type="LOSS",
        exit_rule="scalp_soft_stop_pct",
        profit_rate=-3.65,
        peak_profit=0.31,
        current_ai_score=70,
        held_sec=180,
        dynamic_stop_pct=-3.00,
    )
    assert already_used["should_retry"] is False
    assert already_used["reason"] == "already_used"
    assert already_used["max_per_position"] == 1

    stock_without_count = {
        **stock,
        "stop_line_touch_avg_down_used": False,
        "stop_line_touch_avg_down_count": 0,
    }
    inferred_first_used = state_handlers._evaluate_stop_line_touch_mandatory_avg_down(
        stock_without_count,
        strategy="SCALPING",
        sell_reason_type="LOSS",
        exit_rule="scalp_soft_stop_pct",
        profit_rate=-3.65,
        peak_profit=0.31,
        current_ai_score=70,
        held_sec=180,
        dynamic_stop_pct=-3.00,
    )
    assert inferred_first_used["should_retry"] is True
    assert inferred_first_used["used_count"] == 0

    inferred_prior_avg_down = state_handlers._evaluate_stop_line_touch_mandatory_avg_down(
        {**stock_without_count, "last_add_type": "AVG_DOWN"},
        strategy="SCALPING",
        sell_reason_type="LOSS",
        exit_rule="scalp_soft_stop_pct",
        profit_rate=-3.65,
        peak_profit=0.31,
        current_ai_score=70,
        held_sec=180,
        dynamic_stop_pct=-3.00,
    )
    assert inferred_prior_avg_down["should_retry"] is False
    assert inferred_prior_avg_down["reason"] == "already_used"
    assert inferred_prior_avg_down["used_count"] == 1

    shallow_prior_avg_down = state_handlers._evaluate_stop_line_touch_mandatory_avg_down(
        {
            **stock_without_count,
            "avg_down_count": 1,
            "shallow_volatility_avg_down_count": 1,
            "last_add_type": "AVG_DOWN",
            "last_add_reason": "shallow_volatility_avg_down",
            "reversal_add_used": True,
        },
        strategy="SCALPING",
        sell_reason_type="LOSS",
        exit_rule="scalp_soft_stop_pct",
        profit_rate=-3.65,
        peak_profit=0.31,
        current_ai_score=70,
        held_sec=180,
        dynamic_stop_pct=-3.00,
    )
    assert shallow_prior_avg_down["should_retry"] is True
    assert shallow_prior_avg_down["used_count"] == 0


