def test_late_loss_avg_down_retry_includes_hanall_and_gwangju_like_cases(monkeypatch):
    state_handlers.TRADING_RULES = replace(
        CONFIG,
        SCALP_LATE_LOSS_AVG_DOWN_ENABLED=True,
        SCALP_LATE_LOSS_AVG_DOWN_MIN_PEAK_PCT=0.60,
        SCALP_LATE_LOSS_AVG_DOWN_MIN_GIVEBACK_PCT=0.55,
        SCALP_LATE_LOSS_AVG_DOWN_MIN_ABS_LOSS_PCT=1.50,
        SCALP_LATE_LOSS_AVG_DOWN_MIN_HOLD_SEC=30,
        SCALP_LATE_LOSS_AVG_DOWN_MIN_AI_SCORE=60,
    )

    hanall = state_handlers._evaluate_late_loss_avg_down_retry(
        {"strategy": "SCALPING", **_fresh_holding_score_fields(70)},
        strategy="SCALPING",
        sell_reason_type="LOSS",
        exit_rule="scalp_soft_stop_pct",
        profit_rate=-2.10,
        peak_profit=-0.23,
        current_ai_score=70,
        held_sec=2471,
    )
    gwangju = state_handlers._evaluate_late_loss_avg_down_retry(
        {"strategy": "SCALPING"},
        strategy="SCALPING",
        sell_reason_type="LOSS",
        exit_rule="scalp_hard_stop_pct",
        profit_rate=-2.98,
        peak_profit=1.33,
        current_ai_score=67,
        held_sec=596,
    )
    protect_trailing = state_handlers._evaluate_late_loss_avg_down_retry(
        {"strategy": "SCALPING"},
        strategy="SCALPING",
        sell_reason_type="PROFIT_PROTECT",
        exit_rule="protect_trailing_stop",
        profit_rate=-0.20,
        peak_profit=1.33,
        current_ai_score=67,
        held_sec=596,
    )
    mfe_protect = state_handlers._evaluate_late_loss_avg_down_retry(
        {"strategy": "SCALPING"},
        strategy="SCALPING",
        sell_reason_type="PROFIT_PROTECT",
        exit_rule="scalp_mfe_protect_exit",
        profit_rate=-0.23,
        peak_profit=1.81,
        current_ai_score=74,
        held_sec=515,
    )
    one_used = state_handlers._evaluate_late_loss_avg_down_retry(
        {"strategy": "SCALPING", "avg_down_count": 1, **_fresh_holding_score_fields(70)},
        strategy="SCALPING",
        sell_reason_type="LOSS",
        exit_rule="scalp_soft_stop_pct",
        profit_rate=-2.10,
        peak_profit=-0.23,
        current_ai_score=70,
        held_sec=2471,
    )
    two_used = state_handlers._evaluate_late_loss_avg_down_retry(
        {"strategy": "SCALPING", "stop_line_touch_avg_down_count": 3},
        strategy="SCALPING",
        sell_reason_type="LOSS",
        exit_rule="scalp_soft_stop_pct",
        profit_rate=-2.10,
        peak_profit=-0.23,
        current_ai_score=70,
        held_sec=2471,
    )

    assert hanall["should_retry"] is True
    assert hanall["eligibility_path"] == "deep_loss_retry"
    assert one_used["should_retry"] is True
    assert one_used["used_count"] == 1
    assert one_used["max_per_position"] == 3
    assert two_used["should_retry"] is False
    assert two_used["reason"] == "already_used"
    assert two_used["used_count"] == 3
    assert gwangju == {"should_retry": False, "reason": "hard_safety_exit"}
    assert protect_trailing == {"should_retry": False, "reason": "hard_safety_exit"}
    assert mfe_protect == {"should_retry": False, "reason": "hard_safety_exit"}


